#include <stdio.h>
#include <math.h>
#define PI 3.14159265358979323846
#define MAX_POINTS 500
#define MAX_COORD 1000

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    double points[MAX_POINTS][2];
    for (int i = 0; i < N; i++) {
        scanf("%lf %lf", &points[i][0], &points[i][1]);
    }
    double min_radius = MAX_COORD;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            for (int k = j + 1; k < N; k++) {
                double ax = points[i][0], ay = points[i][1];
                double bx = points[j][0], by = points[j][1];
                double cx = points[k][0], cy = points[k][1];
                double a = sqrt((bx - cx) * (bx - cx) + (by - cy) * (by - cy));
                double b = sqrt((ax - cx) * (ax - cx) + (ay - cy) * (ay - cy));
                double c = sqrt((ax - bx) * (ax - bx) + (ay - by) * (ay - by));
                double s = (a + b + c) / 2;
                double area = sqrt(s * (s - a) * (s - b) * (s - c));
                double radius = (a * b * c) / (4 * area);
                if (radius < min_radius) {
                    min_radius = radius;
                }
            }
        }
    }
    printf("%.6f\n", min_radius);
    return 0;
}

